function getPilarStyle(tipo) {
  if (!tipo) return PILAR_CORES.default;
  const match = tipo.match(/\(([^)]+)\)/);
  if (match) {
    const pilar = match[1].trim();
    for (const key of Object.keys(PILAR_CORES)) {
      if (pilar.includes(key) || key.includes(pilar)) {
        return PILAR_CORES[key] || PILAR_CORES.default;
      }
    }
    return PILAR_CORES[pilar] || PILAR_CORES.default;
  }
  return PILAR_CORES.default;
}

